133	export function collectStats(dbPath: string): StatsSummary {
134	  const db = openReadDb(dbPath);
135	  const counts = getStatsCounts(db);
136	  const topCwds = getTopCwds(db, 10);
137	  db.close();
138	
139	  let dbSizeBytes = 0;
140	  try {
141	    dbSizeBytes = statSync(dbPath).size;
142	  } catch {
143	    dbSizeBytes = 0;
144	  }
145	
146	  return {
147	    sessionCount: counts.sessionCount,
148	    messageCount: counts.messageCount,
149	    earliestStartedAt: counts.earliestStartedAt,
150	    latestEndedAt: counts.latestEndedAt,
151	    topCwds,
152	    indexVersion: INDEX_VERSION,
153	    dbPath,
154	    dbSizeBytes,
155	    lastSyncAt: counts.lastSyncAt,
156	  };
