159	function resolveAnchorSeq(
160	  db: Database,
161	  sessionUuid: string,
162	  seq?: number,
163	  query?: string,
164	): number {
165	  if (typeof seq === "number") {
166	    return seq;
167	  }
168	
169	  if (query) {
170	    const best = searchTopHitInSession(db, sessionUuid, query);
171	    if (best && typeof best.matchSeq === "number") return best.matchSeq;
172	  }
173	
174	  throw new Error("read-range requires explicit session_uuid plus either --seq or --query");
175	}
176	
177	function searchTopHitInSession(db: Database, sessionUuid: string, query: string): FindResult | null {
178	  const rows = searchMessageHits(db, query, 20, sessionUuid);
179	  const result = rerankHits(rows, query, 1)[0];
180	  return result ?? null;
181	}
182	
183	function searchMessageHits(db: Database, query: string, limit: number, sessionUuid?: string): RawHitRow[] {
184	  const normalized = query.trim();
185	  if (!normalized) return [];
186	
187	  const terms = queryTerms(normalized);
188	  // Queries that degenerate to zero tokens (e.g. a single kanji dropped as
189	  // stop-word-like noise, or whitespace only) cannot hit the FTS index. Fall
190	  // back to a bounded LIKE scan so single-character CJK probes still work
191	  // even though they are discouraged.
192	  if (terms.length === 0) {
193	    if (hasCjk(normalized)) return searchByLike(db, normalized, limit, sessionUuid);
194	    return [];
195	  }
196	
197	  return searchByFts(db, terms, limit, sessionUuid);
198	}
199	
200	function searchSessionHits(db: Database, query: string, limit: number): RawHitRow[] {
201	  const normalized = query.trim();
202	  if (!normalized || !tableExists(db, "sessions_fts")) return [];
203	
204	  const terms = queryTerms(normalized);
205	  if (terms.length === 0) return [];
206	
207	  return searchSessionsByFts(db, normalized, terms, limit);
208	}
209	
210	function searchByFts(
211	  db: Database,
212	  terms: string[],
213	  limit: number,
214	  sessionUuid?: string,
215	): RawHitRow[] {
216	  const matchExpr = buildFtsMatch(terms);
217	  const conditions = [`messages_fts MATCH ?`];
218	  const params: SqlParams = [matchExpr];
219	
220	  if (sessionUuid) {
221	    conditions.push("m.session_uuid = ?");
222	    params.push(sessionUuid);
223	  }
224	  params.push(limit);
225	
226	  return db
227	    .query<RawHitRow, typeof params>(`
228	      SELECT
229	        s.session_uuid AS sessionUuid,
230	        s.title AS title,
231	        s.summary_text AS summaryText,
232	        s.cwd AS cwd,
233	        s.started_at AS startedAt,
234	        s.ended_at AS endedAt,
235	        'message' AS matchSource,
236	        m.seq AS matchSeq,
237	        m.role AS matchRole,
238	        m.timestamp AS matchTimestamp,
239	        m.content_text AS contentText,
240	        snippet(messages_fts, 0, '<mark>', '</mark>', '…', 16) AS snippet,
241	        bm25(messages_fts) AS score
242	      FROM messages_fts
243	      JOIN messages m ON m.id = messages_fts.rowid
244	      JOIN sessions s ON s.id = m.session_id
245	      WHERE ${conditions.join(" AND ")}
246	      ORDER BY score
247	      LIMIT ?
248	    `)
249	    .all(...params) as RawHitRow[];
250	}
251	
252	function searchSessionsByFts(
253	  db: Database,
254	  query: string,
255	  terms: string[],
256	  limit: number,
257	): RawHitRow[] {
258	  const matchExpr = buildFtsMatch(terms);
259	  const rows = db
260	    .query<RawHitRow, [string, number]>(`
261	      SELECT
262	        s.session_uuid AS sessionUuid,
263	        s.title AS title,
264	        s.summary_text AS summaryText,
265	        s.cwd AS cwd,
266	        s.started_at AS startedAt,
267	        s.ended_at AS endedAt,
268	        'session' AS matchSource,
269	        NULL AS matchSeq,
270	        'session' AS matchRole,
271	        NULL AS matchTimestamp,
272	        s.title || char(10) || s.summary_text || char(10) || s.compact_text || char(10) || s.reasoning_summary_text AS contentText,
273	        '' AS snippet,
274	        bm25(sessions_fts, 8.0, 3.0, 4.0, 1.2) AS score
275	      FROM sessions_fts
276	      JOIN sessions s ON s.id = sessions_fts.rowid
277	      WHERE sessions_fts MATCH ?
278	      ORDER BY score
279	      LIMIT ?
280	    `)
281	    .all(matchExpr, limit) as RawHitRow[];
282	
283	  return rows.map((row) => ({
284	    ...row,
285	    snippet: makeRawSnippet(row.contentText, query, terms),
286	  }));
287	}
288	
289	function searchByLike(db: Database, query: string, limit: number, sessionUuid?: string): RawHitRow[] {
290	  const conditions = ["lower(m.content_text) LIKE ? ESCAPE '\\'"];
291	  const params: SqlParams = [`%${escapeLike(query.toLowerCase())}%`];
292	  if (sessionUuid) {
293	    conditions.push("m.session_uuid = ?");
294	    params.push(sessionUuid);
295	  }
296	  params.push(limit);
297	
298	  const rows = db
299	    .query<RawHitRow & { contentText: string }, typeof params>(`
300	      SELECT
301	        s.session_uuid AS sessionUuid,
302	        s.title AS title,
303	        s.summary_text AS summaryText,
304	        s.cwd AS cwd,
305	        s.started_at AS startedAt,
306	        s.ended_at AS endedAt,
307	        'message' AS matchSource,
308	        m.seq AS matchSeq,
309	        m.role AS matchRole,
310	        m.timestamp AS matchTimestamp,
311	        m.content_text AS contentText
312	      FROM messages m
313	      JOIN sessions s ON s.id = m.session_id
314	      WHERE ${conditions.join(" AND ")}
315	      ORDER BY s.started_at DESC, m.seq ASC
316	      LIMIT ?
317	    `)
318	    .all(...params) as Array<RawHitRow & { contentText: string }>;
319	
320	  return rows.map((row, index) => ({
321	    ...row,
322	    snippet: makeLikeSnippet(row.contentText, query),
323	    // Negate the ordinal so LIKE rows share the "lower is better" polarity
324	    // with bm25() scores; downstream rerank sorts on row metrics, but any
325	    // code that touches this raw score won't see a sign mismatch.
326	    score: -(index + 1),
327	  }));
328	}
329	
330	function tableExists(db: Database, tableName: string): boolean {
331	  const row = db
332	    .query<unknown, [string]>("SELECT 1 FROM sqlite_master WHERE name = ? LIMIT 1")
333	    .get(tableName);
334	  return Boolean(row);
335	}
336	
337	/**
338	 * Build an FTS5 MATCH expression from already-tokenized terms. Each term is
339	 * quoted and ANDed, giving us intersection semantics across CJK bigrams and
340	 * non-CJK words alike.
341	 */
342	function buildFtsMatch(terms: string[]): string {
343	  return terms.map(quoteFtsTerm).join(" AND ");
344	}
345	
346	function quoteFtsTerm(term: string): string {
347	  // FTS5 treats unquoted * / ^ / NEAR / NOT / AND / OR as operators. Wrapping
348	  // each term in double quotes neutralizes all of them (including *), and we
349	  // escape internal quotes by doubling them. Bigrams stay bigrams.
350	  const escaped = term.replaceAll('"', '""');
351	  return `"${escaped}"`;
352	}
353	
354	// LIKE-path escape stays unchanged: only CJK single-character probes and
355	// empty-token queries fall through to this branch now.
356	function escapeLike(value: string): string {
357	  return value.replaceAll("\\", "\\\\").replaceAll("%", "\\%").replaceAll("_", "\\_");
358	}
359	
360	function makeLikeSnippet(content: string, query: string): string {
361	  const lower = content.toLowerCase();
362	  const target = query.toLowerCase();
363	  const index = lower.indexOf(target);
364	  if (index < 0) return content.slice(0, 160);
365	  const start = Math.max(0, index - 40);
366	  const end = Math.min(content.length, index + target.length + 80);
367	  const prefix = start > 0 ? "…" : "";
368	  const suffix = end < content.length ? "…" : "";
369	  const snippet = content.slice(start, end);
370	  // Re-scan the snippet slice and wrap every occurrence so the returned
371	  // snippet agrees with FTS5's snippet() which highlights all matches.
372	  const highlighted = wrapAllOccurrences(snippet, target);
373	  return `${prefix}${highlighted}${suffix}`;
374	}
375	
376	function makeRawSnippet(content: string, query: string, terms: string[]): string {
377	  const normalizedQuery = query.toLowerCase();
378	  const lower = content.toLowerCase();
379	  const phraseIndex = normalizedQuery ? lower.indexOf(normalizedQuery) : -1;
380	  if (phraseIndex >= 0) {
381	    return snippetAround(content, phraseIndex, query.length, [normalizedQuery]);
382	  }
383	
384	  const termLowers = uniqueNonEmpty(terms.map((term) => term.toLowerCase()));
385	  const termHits = termLowers.flatMap((term) => collectTermHits(lower, term));
386	  if (termHits.length === 0) return content.slice(0, 160);
387	
388	  const bestWindow = termHits
389	    .map((hit) => {
390	      const start = Math.max(0, hit.index - 40);
391	      const end = Math.min(content.length, hit.index + hit.length + 80);
392	      return {
393	        start,
394	        end,
395	        anchor: hit.index,
396	        score: scoreSnippetWindow(lower.slice(start, end), termLowers),
397	      };
398	    })
399	    .sort((left, right) => {
400	      if (right.score !== left.score) return right.score - left.score;
401	      return left.anchor - right.anchor;
402	    })[0];
403	
404	  return snippetWindow(content, bestWindow.start, bestWindow.end, termLowers);
405	}
406	
407	function snippetAround(content: string, index: number, length: number, needleLowers: string[]): string {
408	  const start = Math.max(0, index - 40);
409	  const end = Math.min(content.length, index + length + 80);
410	  return snippetWindow(content, start, end, needleLowers);
411	}
412	
413	function snippetWindow(content: string, start: number, end: number, needleLowers: string[]): string {
414	  const prefix = start > 0 ? "…" : "";
415	  const suffix = end < content.length ? "…" : "";
416	  const snippet = content.slice(start, end);
417	  return `${prefix}${wrapAnyOccurrences(snippet, needleLowers)}${suffix}`;
418	}
419	
420	function collectTermHits(lower: string, termLower: string): Array<{ index: number; length: number }> {
421	  const hits: Array<{ index: number; length: number }> = [];
422	  let cursor = 0;
423	  while (cursor < lower.length) {
424	    const index = lower.indexOf(termLower, cursor);
425	    if (index < 0) break;
426	    hits.push({ index, length: termLower.length });
427	    cursor = index + termLower.length;
428	  }
429	  return hits;
430	}
431	
432	function scoreSnippetWindow(lowerSnippet: string, termLowers: string[]): number {
433	  let distinctTerms = 0;
434	  let totalHits = 0;
435	  let matchedChars = 0;
436	
437	  for (const term of termLowers) {
438	    const hits = collectTermHits(lowerSnippet, term).length;
439	    if (hits > 0) distinctTerms += 1;
440	    totalHits += hits;
441	    matchedChars += hits * term.length;
442	  }
443	
444	  return distinctTerms * 1_000 + matchedChars * 10 + totalHits;
445	}
446	
447	function uniqueNonEmpty(values: string[]): string[] {
448	  return [...new Set(values.filter(Boolean))];
449	}
450	
451	function wrapAnyOccurrences(haystack: string, needleLowers: string[]): string {
452	  const needles = uniqueNonEmpty(needleLowers).sort((left, right) => right.length - left.length);
453	  if (needles.length === 0) return haystack;
454	
455	  const lower = haystack.toLowerCase();
456	  const matches = needles
457	    .flatMap((needle) => collectTermHits(lower, needle))
458	    .sort((left, right) => {
459	      if (left.index !== right.index) return left.index - right.index;
460	      return right.length - left.length;
461	    });
462	
463	  const out: string[] = [];
464	  let cursor = 0;
465	  for (const match of matches) {
466	    if (match.index < cursor) continue;
467	    out.push(haystack.slice(cursor, match.index));
468	    out.push("<mark>");
469	    out.push(haystack.slice(match.index, match.index + match.length));
470	    out.push("</mark>");
471	    cursor = match.index + match.length;
472	  }
473	  out.push(haystack.slice(cursor));
474	  return out.join("");
475	}
476	
477	function wrapAllOccurrences(haystack: string, needleLower: string): string {
478	  if (!needleLower) return haystack;
479	  const out: string[] = [];
480	  let cursor = 0;
481	  const lower = haystack.toLowerCase();
482	  while (cursor < haystack.length) {
483	    const hit = lower.indexOf(needleLower, cursor);
484	    if (hit < 0) {
485	      out.push(haystack.slice(cursor));
486	      break;
487	    }
488	    out.push(haystack.slice(cursor, hit));
489	    out.push("<mark>");
490	    out.push(haystack.slice(hit, hit + needleLower.length));
491	    out.push("</mark>");
492	    cursor = hit + needleLower.length;
493	  }
494	  return out.join("");
495	}
496	
497	// Re-export for callers that still rely on the old helper name.
498	export function isCjkTerm(token: string): boolean {
499	  return isCjkToken(token);
500	}
