1	import type { FindMatchRole, FindResult, MatchSource } from "./types";
2	import { queryTerms } from "./tokenize";
3	
4	export interface RawHitRow {
5	  sessionUuid: string;
6	  title: string;
7	  summaryText: string;
8	  cwd: string;
9	  startedAt: string;
10	  endedAt: string;
11	  matchSource: MatchSource;
12	  matchSeq: number | null;
13	  matchRole: FindMatchRole;
14	  matchTimestamp: string | null;
15	  contentText: string;
16	  snippet: string;
17	  // FTS path: negative bm25(). LIKE path: a small negative ordinal. Either
18	  // way, lower is "better" from the SQL side; we flip the sign during
19	  // rerank so all bonuses stay positive and additive.
20	  score: number;
21	}
22	
23	export interface QueryProfile {
24	  normalizedQuery: string;
25	  terms: string[];
26	  isMultiTerm: boolean;
27	}
28	
29	/**
30	 * Kept for backward compat with callers that still read `kind`. The v3
31	 * scoring pipeline does not branch on kind anymore; it treats `isMultiTerm`
32	 * as a continuous signal instead. Single-term queries are labelled "broad",
33	 * everything else "exact" to preserve existing external tests.
34	 */
35	export function classifyQueryProfile(query: string): QueryProfile & { kind: "broad" | "exact" } {
36	  const normalizedQuery = query.trim().toLowerCase();
37	  const terms = queryTerms(query);
38	  const hasMultipleRawTokens = query.trim().split(/\s+/).filter(Boolean).length >= 2;
39	  const hasDigits = /\d/.test(query);
40	  const hasPathLikeToken = /[\\/._:-]/.test(query);
41	  // "exact" historically meant: user gave us enough signal that we should
42	  // trust phrase matches heavily. Keep that label, but compute it off the
43	  // raw query rather than the tokenized terms so the category stays stable
44	  // for CJK queries that bigram-explode into many tokens.
45	  const kind: "broad" | "exact" = hasMultipleRawTokens || hasDigits || hasPathLikeToken
46	    ? "exact"
47	    : "broad";
48	  return {
49	    kind,
50	    normalizedQuery,
51	    terms,
52	    isMultiTerm: hasMultipleRawTokens,
53	  };
54	}
55	
56	interface SessionAggregate {
57	  row: RawHitRow;
58	  bestRow: RawHitRow;
59	  bestDisplayRow: RawHitRow;
60	  bestRowSignalScore: number;
61	  bestDisplayRowSignalScore: number;
62	  hitCount: number;
63	  sessionHitCount: number;
64	  userHitCount: number;
65	  titlePhrase: boolean;
66	  titleTermHits: number;
67	  cwdTermHits: number;
68	}
69	
70	export function rerankHits(rows: RawHitRow[], query: string, limit: number): FindResult[] {
71	  const profile = classifyQueryProfile(query);
72	  const now = Date.now();
73	  const grouped = new Map<string, SessionAggregate>();
74	
75	  for (const row of rows) {
76	    const signalScore = scoreRow(row, profile);
77	    const existing = grouped.get(row.sessionUuid);
78	    const rowTitleLower = row.title.toLowerCase();
79	    const rowCwdLower = row.cwd.toLowerCase();
80	    const titlePhrase = profile.normalizedQuery.length > 0
81	      && rowTitleLower.includes(profile.normalizedQuery);
82	    const titleTermHits = countMatchedTerms(rowTitleLower, profile.terms);
83	    const cwdTermHits = countMatchedTerms(rowCwdLower, profile.terms);
84	
85	    if (!existing) {
86	      grouped.set(row.sessionUuid, {
87	        row,
88	        bestRow: row,
89	        bestDisplayRow: row,
90	        bestRowSignalScore: signalScore,
91	        bestDisplayRowSignalScore: signalScore,
92	        hitCount: 1,
93	        sessionHitCount: row.matchSource === "session" ? 1 : 0,
94	        userHitCount: row.matchRole === "user" ? 1 : 0,
95	        titlePhrase,
96	        titleTermHits,
97	        cwdTermHits,
98	      });
99	      continue;
100	    }
101	
102	    existing.hitCount += 1;
103	    if (row.matchSource === "session") existing.sessionHitCount += 1;
104	    if (row.matchRole === "user") existing.userHitCount += 1;
105	    existing.titlePhrase = existing.titlePhrase || titlePhrase;
106	    existing.titleTermHits = Math.max(existing.titleTermHits, titleTermHits);
107	    existing.cwdTermHits = Math.max(existing.cwdTermHits, cwdTermHits);
108	    if (signalScore > existing.bestRowSignalScore) {
109	      existing.bestRow = row;
110	      existing.bestRowSignalScore = signalScore;
111	    }
112	    if (shouldUseDisplayRow(existing.bestDisplayRow, row, existing.bestDisplayRowSignalScore, signalScore)) {
113	      existing.bestDisplayRow = row;
114	      existing.bestDisplayRowSignalScore = signalScore;
115	    }
116	  }
117	
118	  const ranked = Array.from(grouped.values())
119	    .map((aggregate) => ({
120	      aggregate,
121	      sessionScore: scoreSession(aggregate, profile, now),
122	    }))
123	    .sort((left, right) => {
124	      if (right.sessionScore !== left.sessionScore) {
125	        return right.sessionScore - left.sessionScore;
126	      }
127	      return getTimestamp(right.aggregate.row.endedAt) - getTimestamp(left.aggregate.row.endedAt);
128	    });
129	
130	  return ranked.slice(0, limit).map(({ aggregate, sessionScore }, index) => ({
131	    rank: index + 1,
132	    sessionUuid: aggregate.row.sessionUuid,
133	    title: aggregate.row.title,
134	    summaryText: aggregate.row.summaryText,
135	    cwd: aggregate.row.cwd,
136	    startedAt: aggregate.row.startedAt,
137	    endedAt: aggregate.row.endedAt,
138	    matchCount: aggregate.hitCount,
139	    matchSource: aggregate.bestDisplayRow.matchSource,
140	    matchSeq: aggregate.bestDisplayRow.matchSeq,
141	    matchRole: aggregate.bestDisplayRow.matchRole,
142	    matchTimestamp: aggregate.bestDisplayRow.matchTimestamp,
143	    score: sessionScore,
144	    snippet: aggregate.bestDisplayRow.snippet,
145	  }));
146	}
147	
148	function shouldUseDisplayRow(
149	  current: RawHitRow,
