```ts
/** 仅当 lock 文件仍是我们刚才看到的那一份时,才删除它。
 *  返回 true 表示 stale lock 已清理(或本身已不存在),调用方可以立即重试 acquire;
 *  返回 false 表示另一个进程已抢到 lock,调用方应回到 polling/timeout 路径。
 *  Why:避免 TOCTOU — 在我们读到 dead pid 与执行删除之间,新进程可能已成功 acquire。
 */
function tryRemoveStaleLock(lockPath: string, expected: SyncLockInfo): boolean {
  const reChecked = readLockInfo(lockPath);
  if (!reChecked) return true;
  if (reChecked.pid !== expected.pid || reChecked.createdAt !== expected.createdAt) {
    return false;
  }
  removeLockIfPresent(lockPath);
  return true;
